import{_ as o,C as n,o as l,c as s,E as a,w as t,a as r,a0 as d}from"./chunks/framework.CkNTPv-z.js";const y=JSON.parse('{"title":"Croatia Legal Rights","description":"Legal rights for transgender people in Croatia","frontmatter":{"layout":"doc","title":"Croatia Legal Rights","description":"Legal rights for transgender people in Croatia"},"headers":[],"relativePath":"europe/croatia/legal-rights.md","filePath":"europe/croatia/legal-rights.md","lastUpdated":null}'),c={name:"europe/croatia/legal-rights.md"};function h(u,e,g,m,p,f){const i=n("Badge");return l(),s("div",null,[a(i,{variant:"red"},{default:t(()=>[...e[0]||(e[0]=[r("Medicalized System",-1)])]),_:1}),a(i,{variant:"yellow"},{default:t(()=>[...e[1]||(e[1]=[r("Moderate Anti-Discrimination",-1)])]),_:1}),e[2]||(e[2]=d('<h1 id="legal-rights-in-croatia" tabindex="-1">Legal Rights in Croatia <a class="header-anchor" href="#legal-rights-in-croatia" aria-label="Permalink to &quot;Legal Rights in Croatia&quot;">​</a></h1><h2 id="gender-recognition" tabindex="-1">Gender Recognition <a class="header-anchor" href="#gender-recognition" aria-label="Permalink to &quot;Gender Recognition&quot;">​</a></h2><p>Croatia operates a <strong>medicalized model</strong> for legal gender recognition. The process requires medical intervention and court approval.</p><h3 id="requirements" tabindex="-1">Requirements <a class="header-anchor" href="#requirements" aria-label="Permalink to &quot;Requirements&quot;">​</a></h3><ul><li>Psychiatric diagnosis of gender dysphoria</li><li><strong>Minimum 1 year</strong> of hormone replacement therapy (HRT)</li><li>Court application with medical evidence</li><li>Psychological evaluation reports</li><li>No explicit sterilization requirement (removed in practice)</li><li>Minimum age: 18</li></ul><h3 id="process" tabindex="-1">Process <a class="header-anchor" href="#process" aria-label="Permalink to &quot;Process&quot;">​</a></h3><ol><li>Initial psychiatric assessment and diagnosis (3-6 months)</li><li>Begin HRT (requires endocrinologist involvement)</li><li>After 1 year of HRT, collect comprehensive medical reports</li><li>Submit application to the municipal court</li><li>Court hearing with medical expert testimony</li><li>Court decision typically takes 3-6 months</li><li>Register the change with the civil registry (Matica)</li></ol><h2 id="name-changes" tabindex="-1">Name Changes <a class="header-anchor" href="#name-changes" aria-label="Permalink to &quot;Name Changes&quot;">​</a></h2><ul><li>Name changes can be requested alongside gender marker change</li><li>Separate name-only changes require a justified reason</li><li>For trans people, the name change requires medical documentation in practice</li><li>Processed through the civil registry office</li></ul><h2 id="anti-discrimination-laws" tabindex="-1">Anti-Discrimination Laws <a class="header-anchor" href="#anti-discrimination-laws" aria-label="Permalink to &quot;Anti-Discrimination Laws&quot;">​</a></h2><p>Croatia has moderate anti-discrimination protections:</p><ul><li><strong>Anti-Discrimination Act (2008)</strong> — Prohibits discrimination based on gender identity</li><li>Gender identity is explicitly listed as a protected ground</li><li><strong>Employment</strong> — Protection in hiring, promotion, dismissal</li><li><strong>Education</strong> — Protection in schools and universities</li><li><strong>Goods and Services</strong> — Access to services</li><li><strong>Housing</strong> — Protection in rental and purchase</li><li>Enforcement is inconsistent, with significant variation between urban and rural areas</li></ul><h2 id="hate-crime-laws" tabindex="-1">Hate Crime Laws <a class="header-anchor" href="#hate-crime-laws" aria-label="Permalink to &quot;Hate Crime Laws&quot;">​</a></h2><ul><li>Croatia&#39;s Criminal Code includes hate crime provisions</li><li>Gender identity is explicitly included as a protected characteristic</li><li>Enhanced penalties for crimes motivated by transphobia</li><li>Reporting rates are low due to distrust of police</li><li>Prosecution rates are moderate</li><li>LGBTQ+ organizations note inconsistent application of the law</li></ul><h2 id="document-recognition" tabindex="-1">Document Recognition <a class="header-anchor" href="#document-recognition" aria-label="Permalink to &quot;Document Recognition&quot;">​</a></h2><ul><li>Updated gender markers on Croatian passports and IDs are recognized</li><li>Croatian passports follow EU standards</li><li>Third gender / &quot;X&quot; marker not available</li><li>Updated documents accepted within the EU</li></ul><h2 id="social-context" tabindex="-1">Social Context <a class="header-anchor" href="#social-context" aria-label="Permalink to &quot;Social Context&quot;">​</a></h2><ul><li>Croatia is socially conservative, especially in rural areas</li><li>Zagreb, Rijeka, and Split are more tolerant</li><li>Pride events have grown significantly in size and acceptance</li><li>EU membership has driven legal improvements</li><li>LGBTQ+ rights remain a contentious political issue</li></ul><h2 id="summary" tabindex="-1">Summary <a class="header-anchor" href="#summary" aria-label="Permalink to &quot;Summary&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Aspect</th><th>Status</th></tr></thead><tbody><tr><td>Gender Recognition</td><td>Medicalized (diagnosis + 1 year HRT + court)</td></tr><tr><td>Surgery Required</td><td>No (removed in practice)</td></tr><tr><td>Third Gender</td><td>Not available</td></tr><tr><td>Anti-Discrimination</td><td>Moderate (explicitly includes gender identity)</td></tr><tr><td>Hate Crime Protections</td><td>Moderate</td></tr></tbody></table><h2 id="resources" tabindex="-1">Resources <a class="header-anchor" href="#resources" aria-label="Permalink to &quot;Resources&quot;">​</a></h2><ul><li><a href="https://www.usud.hr/" target="_blank" rel="noreferrer">Constitutional Court of Croatia</a></li><li><a href="https://zagreb-pride.net/" target="_blank" rel="noreferrer">Zagreb Pride</a></li><li><a href="https://transaid.hr/" target="_blank" rel="noreferrer">TransAid Croatia</a></li><li><a href="https://lori.hr/" target="_blank" rel="noreferrer">LORI - LGBTQ+ Association</a></li><li><a href="https://www.ilga-europe.org/" target="_blank" rel="noreferrer">ILGA-Europe - Croatia Report</a></li></ul>',22))])}const q=o(c,[["render",h]]);export{y as __pageData,q as default};
